// src/api/client.js
import axios from 'axios';

const API_BASE = process.env.REACT_APP_API_URL || '';

const client = axios.create({
  baseURL: API_BASE,
  headers: { 'Content-Type': 'application/json' },
});

client.interceptors.request.use((config) => {
  const token = localStorage.getItem('access');
  if (token) config.headers.Authorization = `Bearer ${token}`;
  return config;
});

client.interceptors.response.use(
  (res) => res,
  async (error) => {
    const original = error.config;
    if (error.response?.status === 401 && !original._retry) {
      original._retry = true;
      try {
        const refresh = localStorage.getItem('refresh');
        const { data } = await axios.post(`${API_BASE}/api/admin/auth/token/refresh/`, { refresh });
        localStorage.setItem('access', data.access);
        original.headers.Authorization = `Bearer ${data.access}`;
        return client(original);
      } catch {
        localStorage.clear();
        window.location.href = '/login';
      }
    }
    return Promise.reject(error);
  }
);

export default client;

// ── Auth ─────────────────────────────────────────────────────────────────────
export const authAPI = {
  login:           (phone_number, password) =>
    client.post('/api/admin/auth/login/', { phone_number, password }),
  registerInstructor: (data) =>
    client.post('/api/admin/auth/register/', data),
  sendOTP:         (phone_number) =>
    client.post('/api/admin/auth/send-otp/', { phone_number }),
  verifyOTP:       (phone_number, code) =>
    client.post('/api/admin/auth/verify/', { phone_number, code }),
  forgotPassword:  (phone_number) =>
    client.post('/api/admin/auth/forgot-password/', { phone_number }),
  resetPassword:   (phone_number, code, new_password) =>
    client.post('/api/admin/auth/reset-password/', { phone_number, code, new_password }),
};

// ── Instructor ────────────────────────────────────────────────────────────────
export const instructorAPI = {
  // Профиль
  getProfile:    ()     => client.get('/api/admin/instructor/profile/'),
  updateCar:     (data) => client.patch('/api/admin/instructor/car/', data),
  updateLimit:   (data) => client.patch('/api/admin/instructor/limit/', data),

  // Слоты практики
  // params: { date?: 'YYYY-MM-DD', week?: 'YYYY-MM-DD' }
  getSlots:      (params) => client.get('/api/admin/instructor/slots/', { params }),
  createSlot:    (data)   => client.post('/api/admin/instructor/slots/', data),
  getSlot:       (id)     => client.get(`/api/admin/instructor/slots/${id}/`),
  updateSlot:    (id, data) => client.patch(`/api/admin/instructor/slots/${id}/`, data),
  deleteSlot:    (id)     => client.delete(`/api/admin/instructor/slots/${id}/`),

  // Студенты и занятия
  getStudents:   ()       => client.get('/api/admin/instructor/students/'),
  // params: { date?: 'YYYY-MM-DD' }
  getUpcoming:   (params) => client.get('/api/admin/instructor/upcoming/', { params }),

  // Уведомления
  getNotifications: ()   => client.get('/api/admin/instructor/notifications/'),
  markRead:      (id)    => client.patch(`/api/admin/instructor/notifications/${id}/read/`),
};

// ── Admin — Students ──────────────────────────────────────────────────────────
export const studentsAPI = {
  list:             ()        => client.get('/api/admin/students/'),
  detail:           (userId)  => client.get(`/api/admin/students/${userId}/`),
  update:           (userId, data) => client.patch(`/api/admin/students/${userId}/`, data),
  assignInstructor: (userId, instructor_id) =>
    client.post(`/api/admin/students/${userId}/assign-instructor/`, { instructor_id }),
  assignGroup:      (userId, group_id) =>
    client.post(`/api/admin/students/${userId}/assign-group/`, { group_id }),
};

// ── Admin — Schedule ──────────────────────────────────────────────────────────
export const scheduleAPI = {
  driveSlots:  ()     => client.get('/api/admin/schedule/drive-slots/'),
  createSlot:  (data) => client.post('/api/admin/schedule/drive-slots/', data),
  deleteSlot:  (id)   => client.delete(`/api/admin/schedule/drive-slots/${id}/`),
  upcoming:    ()     => client.get('/api/admin/schedule/upcoming/'),
  allGroups:   ()     => client.get('/api/admin/schedule/groups/all/'),
};

// ── Admin — Groups ────────────────────────────────────────────────────────────
export const groupsAPI = {
  list:        ()          => client.get('/api/admin/groups/'),
  create:      (data)      => client.post('/api/admin/groups/create/', data),
  update:      (id, data)  => client.patch(`/api/admin/groups/${id}/`, data),
  delete:      (id)        => client.delete(`/api/admin/groups/${id}/delete/`),
  addSchedule: (id, data)  => client.post(`/api/admin/groups/${id}/schedule/`, data),
};

// ── Admin — Invoices ──────────────────────────────────────────────────────────
export const invoicesAPI = {
  list:   (params) => client.get('/api/admin/invoices/', { params }),
  create: (data)   => client.post('/api/admin/invoices/create/', data),
  update: (id, status) => client.patch(`/api/admin/invoices/${id}/`, { status }),
};

// ── Admin — Referral ──────────────────────────────────────────────────────────
export const referralAPI = {
  students: ()   => client.get('/api/admin/referral/students/'),
  payBonus: (id) => client.post(`/api/admin/referral/students/${id}/pay-bonus/`),
};
